-- Seed do instrumento proprietário V2. Rode após as migrations iniciais.

on conflict (code) do update set version = excluded.version, title = excluded.title, status = excluded.status, methodology_status = excluded.methodology_status, source_notes = excluded.source_notes;

with q as (select id from public.questionnaires where code = 'PSICO_V2')
on conflict (questionnaire_id, code) do update set name = excluded.name, description = excluded.description, sort_order = excluded.sort_order;

with q as (select id from public.questionnaires where code = 'PSICO_V2'), d as (select id, code from public.domains where questionnaire_id = (select id from q))
on conflict (questionnaire_id, code) do update set domain_id = excluded.domain_id, text = excluded.text, question_type = excluded.question_type, direction = excluded.direction, is_critical = excluded.is_critical, is_required = excluded.is_required, sort_order = excluded.sort_order;
